async (page) => {
  await page.evaluate((idx) => {
    document.getElementById('inventory-button').click();
    setTimeout(() => {
      const slots = document.querySelectorAll('.item-slot');
      if (slots[idx]) slots[idx].click();
      setTimeout(() => {
        const btn = document.querySelector('.action-equip');
        if (btn) btn.click();
        setTimeout(() => document.getElementById('inventory-button').click(), 500);
      }, 800);
    }, 800);
  }, 1); // slot index 1 = Iron Axe
  await page.waitForTimeout(2500);
  return 'Equipped Iron Axe';
}

async (page) => {
  // Try to equip via direct game inventory API
  const result = await page.evaluate(() => {
    try {
      const inv = window.game.menu.getInventory();
      // Try select then equip
      inv.select(1);
      const equip = inv.equip ? inv.equip(1) : null;
      return JSON.stringify({ inv_methods: Object.getOwnPropertyNames(Object.getPrototypeOf(inv)).filter(m => typeof inv[m] === 'function'), select_result: 'done', equip_result: equip });
    } catch(e) {
      return JSON.stringify({ error: e.message });
    }
  });
  return result;
}
